import React, { useState } from "react";
import style from "./Header.module.css";
import Link from "./link/Link.jsx";
import Logo from "./logo/Logo";
import { GrLanguage } from "@react-icons/all-files/gr/GrLanguage";
import { createUseStyles } from "react-jss";

const styles = createUseStyles({
  list: {
    top: "50px",
    position: "absolute",
    color: "aliceblue",
    right: "30px",
    backgroundColor: "#464646",
    fontSize: "12pt",
    listStyle: "none",
    padding: "20px",
    display: "flex",
    flexDirection: "column",
    gap: "10px",
    display: "none",
  },
  active: {
    display: "block",
  },
});

const Header = () => {
  const classes = styles();
  const [lang, setLang] = useState(false);
  return (
    <header className={style.header}>
      <div>
        <Logo />
      </div>
      <menu className={style.menu}>
        <ul className={style.ul}>
          <Link text="О проекте" to="/" />
          <Link text="Портфолио" to="/works" />
          <Link text="Обучение" to="/learning" />
          <Link text="Общение" to="/chat" />
          <GrLanguage
            onClick={() => setLang(!lang)}
            size={"25px"}
            className={style.lang}
          />
          <ul
            className={
              lang ? [classes.list, classes.active].join(``) : [classes.list]
            }
          >
            <li>Беларуская</li>
            <li>Русский</li>
          </ul>
        </ul>
      </menu>
    </header>
  );
};

export default Header;
